import{_ as a,o as r,c as t,a2 as o}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"ADR-001 — Three.js r128 as 3D renderer","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-001.md","filePath":"adr/ADR-001.md"}'),n={name:"adr/ADR-001.md"};function i(s,e,d,l,c,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-001-—-three-js-r128-as-3d-renderer" tabindex="-1">ADR-001 — Three.js r128 as 3D renderer <a class="header-anchor" href="#adr-001-—-three-js-r128-as-3d-renderer" aria-label="Permalink to &quot;ADR-001 — Three.js r128 as 3D renderer&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-01 TA anchor · §stack · §constraints</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Four of the six screens require real-time 3D rendering in the browser. The solar system explorer, mission arc, and moon map all use Three.js. A version must be pinned to ensure consistent behaviour and avoid breaking changes.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Use Three.js r128, bundled locally in production. Not a newer version. Not a different WebGL library.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>r128 was the version used throughout prototype development. All prototype code is validated against r128. <code>THREE.CapsuleGeometry</code> does not exist in r128 — this constraint is already known and worked around in the prototypes. Upgrading to a later version requires auditing four 3D screens for breaking changes. That audit is out of scope for v1.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li>Three.js r140+ — introduces new geometries and API changes; requires full audit of existing code. Not worth it for v1.</li><li>Babylon.js — different API entirely; would require rewriting all 3D code from scratch.</li><li>Raw WebGL — no value for this use case; Three.js is the right level of abstraction.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: all prototype code ports directly; no breaking changes to manage. Negative: r128 is several versions behind current; some newer Three.js features unavailable.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p>Bundle via npm: <code>three@0.128.0</code>. Do not load from CDN in production (prototypes use CDN; production bundling is handled by Vite via SvelteKit per ADR-012).</p>',14)])])}const m=a(n,[["render",i]]);export{p as __pageData,m as default};
